// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if(isLoading){
		setTimeout(shoHideFields, 300);
		return;
	} else if(oldValue != newValue){
		setTimeout(shoHideFields, 300);
	}

	function shoHideFields() {
		var ajax  = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'getDefaultFormViewForTaskType');
		ajax.addParam('sysparm_u_tasker_type',g_form.getValue('tasker_type'));
		ajax.getXML(f_return_defaultFormViewForType);			
	}

	function f_return_defaultFormViewForType(response){
		try{
			var defaultFormViewId = response.responseXML.documentElement.getAttribute("answer");
			g_form.setValue("u_servicenow_form_view",defaultFormViewId);
		}catch(e){
			jslog(e);
		}	
	}		
}
